const lead = $input.first().json;
let score = 0;
if (lead.website) score += 20;
if (lead.reviews_count > 20) score += 20;
if (lead.rating) score += 10;
if (lead.phone) score += 10;
if (lead.email) score += 15;
if (lead.intent_score) score += 15;
if (lead.category) score += 10;
return [{ json: { ...lead, completeness_score: score } }];

const lead = $('Calculate Completeness Score').first().json;
const websiteNode = $('Fetch Website');
const apolloNode = $('Apollo Enrichment');

let websiteContent = '';
try {
  const html = websiteNode.first()?.json?.data || websiteNode.first()?.json?.body || '';
  // Strip HTML tags and take first 500 chars
  websiteContent = String(html).replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim().substring(0, 500);
} catch(e) {}

let apolloData = {};
try {
  const apollo = apolloNode.first()?.json?.person || apolloNode.first()?.json || {};
  apolloData = {
    apollo_title: apollo.title || '',
    apollo_headline: apollo.headline || '',
    apollo_seniority: apollo.seniority || '',
    apollo_departments: (apollo.departments || []).join(', '),
    apollo_company_size: apollo.organization?.estimated_num_employees || '',
    apollo_company_industry: apollo.organization?.industry || '',
    apollo_company_revenue: apollo.organization?.annual_revenue_printed || ''
  };
} catch(e) {}

return [{
  json: {
    lead_id: lead.id,
    business_name: lead.company || '',
    category: lead.category || lead.industry || '',
    city: lead.location || '',
    rating: lead.rating || 'N/A',
    review_count: lead.reviews_count || 0,
    website: lead.website || '',
    phone: lead.phone || '',
    email: lead.email || '',
    intent_score: lead.intent_score || 'N/A',
    first_name: lead.first_name || '',
    last_name: lead.last_name || '',
    job_title: lead.job_title || '',
    website_content: websiteContent,
    ...apolloData,
    completeness_score: lead.completeness_score
  }
}];

const response = $input.first().json;
const content = response.content[0].text;
const intelligence = JSON.parse(content);
const leadId = $('Webhook').first().json.body.lead_id || $('Webhook').first().json.lead_id;
return [{ json: { intelligence, lead_id: leadId } }];

// Low completeness path - return with low confidence flag
const lead = $input.first().json;
return [{
  json: {
    lead_id: lead.id,
    business_name: lead.company || '',
    category: lead.category || lead.industry || '',
    city: lead.location || '',
    rating: lead.rating || 'N/A',
    review_count: lead.reviews_count || 0,
    website: lead.website || '',
    phone: lead.phone || '',
    email: lead.email || '',
    intent_score: lead.intent_score || 'N/A',
    first_name: lead.first_name || '',
    last_name: lead.last_name || '',
    job_title: lead.job_title || '',
    website_content: '',
    completeness_score: lead.completeness_score,
    low_confidence: true
  }
}];
